const input = $input.first().json;
const body = input.body || input;

const updates = [];
const fields = [
  'nombre_academia', 'nombre_profe', 'email', 'telefono',
  'ubicacion_direccion', 'ubicacion_localidad', 'horario_atencion',
  'banco', 'cbu', 'alias', 'linktree_url',
  'instagram', 'facebook', 'politica_cancelacion',
  'politica_recuperacion', 'politica_reembolso'
];

for (const field of fields) {
  const value = body[field];
  if (value !== undefined && value !== null && value !== '') {
    const escaped = String(value).replace(/'/g, "''");
    updates.push(`${field} = '${escaped}'`);
  }
}

const query = updates.length > 0
  ? `UPDATE academia_config SET ${updates.join(', ')}, updated_at = NOW() WHERE id = 1 RETURNING *;`
  : null;

return [{
  json: {
    query,
    hasUpdates: updates.length > 0
  }
}];

const result = $input.first().json;

const config = {
  nombre_academia: result.nombre_academia || '',
  nombre_profe: result.nombre_profe || '',
  email: result.email || '',
  telefono: result.telefono || '',
  ubicacion_direccion: result.ubicacion_direccion || '',
  ubicacion_localidad: result.ubicacion_localidad || '',
  horario_atencion: result.horario_atencion || '',
  banco: result.banco || '',
  cbu: result.cbu || '',
  alias: result.alias || '',
  linktree_url: result.linktree_url || '',
  instagram: result.instagram || '',
  facebook: result.facebook || '',
  politica_cancelacion: result.politica_cancelacion || '',
  politica_recuperacion: result.politica_recuperacion || '',
  politica_reembolso: result.politica_reembolso || ''
};

return [{
  json: {
    success: true,
    message: 'Configuración actualizada exitosamente',
    config
  }
}];

return [{
  json: {
    success: false,
    message: 'No hay campos para actualizar',
    config: {}
  }
}];
